(window.webpackJsonp=window.webpackJsonp||[]).push([[237],{864:function(n,e){n.exports="\x3c!-- \ntitle: 21-JS基础\nsort: \n--\x3e \n\n# JavaScript基础\n\n## 字面量\n\n```js\n// 数字\n4.04\t\n314e-2\t\nNaN\t\nInfinity\n\n// 字符串\n'fzf404'\t\n\"fzf404\"\n\n// 数组 Array\n[2,3,5,7,11]\n\n// 对象 Object\n{ \n    name:'fzf', \n    age:17, \n    country:'China'\n}\n```\n\n## 变量\n\n```js\nvar x, len;\nx = 5;\nlen = 404;\n```\n\n### 字符串\n\n```js\n// 字符串\nvar txt = \"ABCDEFGHIJKLMNOPQRSTUVWXYZ\";\nvar sln = txt.length;\n\n// 多行字符串\n`这是一个\n多行\n字符串`\n\n// 连接\nvar name = '小明';\nvar age = 20;\nvar message = `你好, ${name}, 你今年${age}岁了!`;\n\n// 转义\n \"We are the so-called \\\"Vikings\\\" from the north.\"\n'\\u4e2d\\u6587'; // ASCII 完全等同于 '中文'\n'\\x41'; // Unicode 完全等同于 'A'\n\n// 变成对象\nvar y = new String(\"John\");\n# 不要创建 String 对象。它会拖慢执行速度，并可能产生其他副作用\n```\n\n### 字符串常用方法\n\n| 方法                | 描述                                                         |\n| :------------------ | :----------------------------------------------------------- |\n| charAt()            | 返回指定索引位置的字符                                       |\n| charCodeAt()        | 返回指定索引位置字符的 Unicode 值                            |\n| concat()            | 连接两个或多个字符串，返回连接后的字符串                     |\n| fromCharCode()      | 将 Unicode 转换为字符串                                      |\n| indexOf()           | 返回字符串中检索指定字符第一次出现的位置                     |\n| lastIndexOf()       | 返回字符串中检索指定字符最后一次出现的位置                   |\n| localeCompare()     | 用本地特定的顺序来比较两个字符串                             |\n| match()             | 找到一个或多个正则表达式的匹配                               |\n| replace()           | 替换与正则表达式匹配的子串                                   |\n| search()            | 检索与正则表达式相匹配的值                                   |\n| slice()             | 提取字符串的片断，并在新的字符串中返回被提取的部分           |\n| split()             | 把字符串分割为子字符串数组                                   |\n| substr()            | 从起始索引号提取字符串中指定数目的字符                       |\n| substring()         | 提取字符串中两个指定的索引号之间的字符                       |\n| toLocaleLowerCase() | 根据主机的语言环境把字符串转换为小写，只有几种语言（如土耳其语）具有地方特有的大小写映射 |\n| toLocaleUpperCase() | 根据主机的语言环境把字符串转换为大写，只有几种语言（如土耳其语）具有地方特有的大小写映射 |\n| toLowerCase()       | 把字符串转换为小写                                           |\n| toString()          | 返回字符串对象值                                             |\n| toUpperCase()       | 把字符串转换为大写                                           |\n| trim()              | 移除字符串首尾空白                                           |\n| valueOf()           | 返回某个字符串对象的原始值                                   |\n\n- 例子\n\n```js\nvar x = \"JohnJohn\";              // x 是字符串\ny = x.charAt(2); // h\ny = x.charCodeAt(2); // 104\ny = x.concat(y, y); // JohnJohn104104, x+y+y\ny = x.indexOf('h'); // 2, 索引从0开始\ny = x.lastIndexOf('h'); // 6\ny = x.slice();\ny = x.split('o'); //J,hnJ,hn\ny = x.substr(2); // hnJohn\ny = x.substring(2,4) // hn，[2,3]\ny = x.toLocaleLowerCase(); // johnjohn,小写\ny = x.toLocaleUpperCase(); // JOHNJOHN,大写\ny = x.toString(); // 转成Stirng\ny = x.toUpperCase(); // JOHNJOHN,大写\ny = x.trim(); // JohnJohn,去除两端的空格\ny = x.valueOf(); // 返回某个字符串对象的原始值\n```\n\n### 数组\n\n```js\nvar arr = [1, 2, 3];\narr.length; // 3\n// 修改长度\narr.length = 6;\t// arr变为[1, 2, 3, undefined, undefined, undefined]\narr.length = 2;\t// arr变为[1, 2]\narr[5] = 'x';\t// arr变为[1, 2, undefined, undefined, undefined, 'x']\n\nvar arr = [10, 20, '30', 'xyz'];\narr.indexOf(10); // 元素10的索引为0\narr.indexOf(20); // 元素20的索引为1\narr.indexOf(30); // 元素30没有找到，返回-1\narr.indexOf('30'); // 元素'30'的索引为2\n\n// 截取数组\nvar arr = ['A', 'B', 'C', 'D', 'E', 'F', 'G'];\narr.slice(0, 3); // 从索引0开始，到索引3结束，但不包括索引3: ['A', 'B', 'C']\narr.slice(3); // 从索引3开始到结束: ['D', 'E', 'F', 'G']\n\n// push pop unshift shift\n压入，取出，头部添加，取出\n\n// sort 排序\n// reverse\t反转\n// splice(起始位置，删除量，添加的元素)\n// concat\t连接\n// join\nvar arr = ['A', 'B', 'C', 1, 2, 3];\narr.join('-'); // 'A-B-C-1-2-3'\n```\n\n## 函数\n\n```js\nfunction Func(a,b){\n    return a*b;\n}\n```\n\n## 数据类型\n\n```js\n// 数组\nvar cars=new Array();\ncars[0]=\"Saab\";\ncars[1]=\"Volvo\";\ncars[2]=\"BMW\";\n// 或者\nvar cars=[\"Saab\",\"Volvo\",\"BMW\"];\n\n// 对象\nvar person={firstname:\"fzf\", lastname:\"nmd\", id:404；\nname=person.lastname;\nname=person[\"lastname\"];\n```\n\n## 对象\n\n> 对象拥有属性和方法\n>\n> JavaScript 对象是变量【键值对】的容器。\n\n```js\n// 创建对象\nvar person = {\n    firstName: \"John\",\n    lastName : \"Doe\",\n    id : 5566,\n    fullName : function() \n\t{\n       return this.firstName + \" \" + this.lastName;\n    }\n};\n// 访问\nperson.lastName;\nperson[\"lastName\"];\nperson.fullName()\n'age' in person;\t// false\n```\n\n```js\nvar obj = {\n    name: \"Carrot\",\n    details: {\n        color: \"orange\",\n        size: 12\n    }\n}\n\nobj.details.color; // orange\nobj[\"details\"][\"size\"]; // 12\n```\n\n### 对象原型\n\n```js\nfunction Person(name, age) {\n  this.name = name;\n  this.age = age;\n}\n\n// 定义一个对象\nvar You = new Person(\"You\", 24); \n// 我们创建了一个新的 Person，名称是 \"You\" \n// (\"You\" 是第一个参数, 24 是第二个参数..)\n```\n\n## 事件\n\n> 在事件触发时 JavaScript 可以执行一些代码。\n\n```js\n// 自攻\n<button onclick=\"this.innerHTML=Date()\">现在的时间是?</button>\n\n// 插入\n<button onclick=\"getElementById('demo').innerHTML=Date()\">现在的时间是?</button>\n<p id=\"demo\"></p>\n\n// 套装后插入\n<button onclick=\"displayDate()\">点这里</button>\n<script>\nfunction displayDate(){\n\tdocument.getElementById(\"demo\").innerHTML=Date();\n}\n<\/script>\n<p id=\"demo\"></p>\n```\n\n### 常见事件\n\n| 事件        | 描述                         |\n| :---------- | :--------------------------- |\n| onchange    | HTML 元素改变                |\n| onclick     | 用户点击 HTML 元素           |\n| onmouseover | 用户在一个HTML元素上移动鼠标 |\n| onmouseout  | 用户从一个HTML元素上移开鼠标 |\n| onkeydown   | 用户按下键盘按键             |\n| onload      | 浏览器已完成页面的加载       |\n\n## 运算符\n\n> ==\t等于(会转换类型后比较)\n>\n> ===\t绝对等于（值和类型均相等）\n\n```js\nNaN === NaN; // false\nisNaN(NaN);\t// true\n```\n\n## 语句\n\n```js\nif (condition1)\n{\n\t当条件 1 为 true 时执行的代码\n}\nelse if (condition2)\n{\n\t当条件 2 为 true 时执行的代码\n}\nelse\n{\n\t当条件 1 和 条件 2 都不为 true 时执行的代码\n}\n\n\nconst condition = 2\n// let 声明一个块级作用域的本地变量\nlet obj = {\n'1' : () => { document.write(1) },\n'2' : () => { document.write(2) },\n'3' : () => { document.write(3) },\n}\nobj[condition]()\n\n\nswitch(n)\n{\n    case 1:\n        执行代码块 1\n        break;\n    case 2:\n        执行代码块 2\n        break;\n    default:\n        与 case 1 和 case 2 不同时执行的代码\n}\n\n\nfor (语句 1; 语句 2; 语句 3)\n{\n    被执行的代码块\n}\n\n\nwhile (条件)\n{\n    需要执行的代码\n}\n\n// break 语句用于跳出循环。\n// continue 用于跳过循环中的一个迭代。\n```\n\n## 标签\n\n```js\nfoo: {\n  console.log(1);\n  // 跳出\n  break foo;\n  console.log('本行不会输出');\n}\nconsole.log(2);\n```\n\n"}}]);